const incoming = msg.payload;
let body = incoming;
if (typeof body === 'string') {
  try { body = JSON.parse(body); }
  catch (e) {
    const r = { payload: { ok: false, error: 'invalid JSON' }, statusCode: 400, req: msg.req };
    return [null, r];
  }
}
const id = body.device_id;
const st = body.state;
if (!id || !st) {
  return [null, { req: msg.req, statusCode: 400, payload: { ok: false, error: 'device_id and state required' } }];
}
const mqttPayload = { state: st };
if (body.duration_sec != null) mqttPayload.validFor = Number(body.duration_sec);
if (body.validFor != null) mqttPayload.validFor = Number(body.validFor);
if (body.validUntil != null) mqttPayload.validUntil = Number(body.validUntil);
const topic = 'devices/' + id + '/cmd';
const toBroker = { topic, payload: mqttPayload };
const toHttp = {
  req: msg.req,
  statusCode: 200,
  headers: { 'Content-Type': 'application/json' },
  payload: { ok: true, topic, forwarded: mqttPayload }
};
return [toBroker, toHttp];

const parts = msg.topic.split('/');
const id = parts.length > 1 ? parts[1] : '';
let data = msg.payload;
if (typeof data === 'string') {
  try { data = JSON.parse(data); }
  catch (e) { data = { raw: data }; }
}
global.set('lastTelemetry_' + id, data);
return null;

const id = msg.req.query.device_id;
if (!id) {
  msg.statusCode = 400;
  msg.payload = { ok: false, error: 'device_id query required' };
  return msg;
}
const row = global.get('lastTelemetry_' + id);
if (row == null) {
  msg.statusCode = 404;
  msg.payload = { ok: false, error: 'no telemetry yet for ' + id };
  return msg;
}
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = row;
return msg;
